    10→import { StyleAlternativesService } from '@modules/db/style-alternatives/style-alternatives.service';
    11→import { StyleColorsService } from '@modules/db/style-colors/style-colors.service';
    12→import { IStyleColorBase } from '@modules/db/style-colors/types/style-color.base.interface';
    13→import { StylesService } from '@modules/db/styles/styles.service';
    14→import { IStylesMvBase } from '@modules/db/styles-mv/types/styles-mv.base.interface';
