    31→@Injectable()
    32→export class RelatedProductsService {
    33→	private readonly logger = new Logger(RelatedProductsService.name);
    34→
    35→	constructor(
    36→		private readonly algoliaService: AlgoliaService,
    37→		private readonly colorMatchWorkerService: ColorMatchWorkerService,
    38→		private readonly styleAlternativesService: StyleAlternativesService,
    39→		private readonly metricsService: MetricsService,
    40→		private readonly productHydrationService: ProductHydrationService,
    41→		private readonly styleColorsService: StyleColorsService,
    42→		private readonly stylesService: StylesService,
    43→	) {}
    44→
    45→	private async getCurrentColorStyle(
    46→		styleId: number,
    47→		colorId?: number,
    48→	): Promise<IStyleColorBase | null> {
    49→		if (colorId) {
    50→			const styleByColor = await this.styleColorsService.getStyleByStyleAndColorId({
    51→				styleId,
    52→				colorId,
    53→			});
    54→			if (styleByColor) {
    55→				return styleByColor;
    56→			}
    57→		}
    58→
    59→		const style = await this.styleColorsService.getStyleByStyleId({ styleId });
    60→		if (!style) {
    61→			this.logger.warn('No style found', { styleId });
    62→		}
    63→		return style;
    64→	}
    65→
    66→	private async applyColorMatching(
    67→		products: IRelatedProduct[],
    68→		mvRecords: Map<number, IStylesMvBase>,
    69→		currentStyleColor: IStyleColorBase,
    70→	): Promise<IRelatedProduct[]> {
    71→		const colorCache = new Map<
    72→			number,
    73→			ReturnType<typeof this.productHydrationService.convertMvColorsToProductColors>
    74→		>();
    75→
    76→		return Promise.all(
    77→			products.map(async (product) => {
    78→				const mv = mvRecords.get(product.style_id);
    79→				let colors = colorCache.get(product.style_id);
    80→				if (!colors) {
    81→					colors = this.productHydrationService.convertMvColorsToProductColors({
    82→						colors: mv?.colors ?? null,
    83→					});
    84→					colorCache.set(product.style_id, colors);
    85→				}
    86→				if (colors.length > 0) {
    87→					const closestColorId = await this.colorMatchWorkerService.findClosestColorId({
    88→						color: currentStyleColor,
    89→						palette: colors,
    90→					});
    91→					const closestColor = colors.find((c) => c.id === closestColorId);
    92→					if (closestColor) {
    93→						return {
    94→							...product,
    95→							color: closestColorId,
    96→							image_src: closestColor.image_url ?? product.image_src,
    97→						};
    98→					}
    99→				}
   100→				return product;
   101→			}),
   102→		);
   103→	}
   104→
   105→	@LogExecution({
   106→		logParams: false,
   107→		logResponse: false,
   108→		logExecutionTime: false,
   109→	})
   110→	async getRelatedProducts({
   111→		productId,
   112→		query,
   113→	}: {
   114→		productId: string;
   115→		query: RelatedProductsQueryDto;
   116→	}): Promise<RelatedProductsResponseDto> {
   117→		if (!productId || productId.trim() === '') {
   118→			this.logger.error('Product ID is required to fetch related products');
   119→			throw new BadRequestException('Product ID is required');
   120→		}
   121→
   122→		const numericProductId = Number(productId);
   123→		if (!Number.isInteger(numericProductId) || numericProductId <= 0) {
   124→			this.logger.error(`Invalid Product ID format: ${productId}`);
   125→			throw new BadRequestException(
   126→				`Product ID must be a valid positive integer, received: ${productId}`,
   127→			);
   128→		}
   129→
   130→		const { limit, colorId } = query;
   131→
   132→		try {
   133→			const styleIds = await this.algoliaService.getRelatedProductIds({
   134→				productId: numericProductId,
   135→			});
   136→			this.logger.debug('[getRelatedProducts] Algolia returned related IDs', {
   137→				count: styleIds.length,
   138→			});
   139→
   140→			if (styleIds.length === 0) {
   141→				throw new NotFoundException(
   142→					`No related products found for product ID: ${productId}`,
   143→				);
   144→			}
   145→
   146→			const [currentStyleColor, { products, mvRecords }] = await Promise.all([
   147→				this.getCurrentColorStyle(numericProductId, colorId),
   148→				this.productHydrationService.hydrateProductsWithColors({
   149→					styleIds,
   150→				}),
   151→			]);
   152→
   153→			const relatedProducts = currentStyleColor
   154→				? await this.applyColorMatching(products, mvRecords, currentStyleColor)
   155→				: products;
   156→			this.logger.debug('[getRelatedProducts] Hydration complete', {
   157→				hydratedCount: relatedProducts.length,
   158→			});
   159→
   160→			if (relatedProducts.length === 0) {
   161→				throw new NotFoundException(
   162→					`No related products found for product ID: ${productId}`,
   163→				);
   164→			}
   165→
   166→			return {
   167→				product_id: productId,
   168→				related_products: relatedProducts.slice(0, limit),
   169→				color_id: colorId ?? null,
   170→			};
   171→		} catch (error: unknown) {
   172→			const err = error instanceof Error ? error : new Error(String(error));
   173→			this.logger.error(
   174→				`Error fetching related products from Algolia for productId ${productId}, colorId ${colorId}: ${err.message}`,
   175→				err.stack,
   176→			);
   177→
   178→			await this.metricsService.incrementDailyCounter({
   179→				metricType: dailyTrackingKeys.MMS_REQUESTS,
   180→			});
   181→
   182→			const [alternativeStyleIds, currentStyleColor] = await Promise.all([
   183→				this.styleAlternativesService.getAlternativeStyleIds({
   184→					styleId: numericProductId,
   185→				}),
   186→				this.getCurrentColorStyle(numericProductId, colorId),
   187→			]);
   188→			this.logger.debug('[getRelatedProducts] DB alternatives fetched', {
   189→				count: alternativeStyleIds.length,
   190→			});
   191→
   192→			if (alternativeStyleIds.length === 0) {
   193→				this.logger.warn(`No DB alternatives found for product ID: ${productId}`);
   194→				return {
   195→					product_id: productId,
   196→					related_products: [],
   197→					mms_fallback: true,
   198→					color_id: colorId ?? null,
   199→				};
   200→			}
   201→
   202→			const alternatives = await this.productHydrationService.hydrateProducts({
   203→				styleIds: alternativeStyleIds,
   204→				currentStyleColor,
   205→				activeOnly: true,
   206→			});
   207→
   208→			this.logger.log('[getRelatedProducts] Fallback completed', {
   209→				productId,
   210→				fallbackCount: Math.min(alternatives.length, limit ?? alternatives.length),
   211→			});
   212→
   213→			return {
   214→				product_id: productId,
   215→				related_products: alternatives.slice(0, limit),
   216→				mms_fallback: true,
   217→				color_id: colorId ?? null,
   218→			};
   219→		}
   220→	}
