   222→	async getBrandProducts(
   223→		query: BrandProductsQueryDto,
   224→	): Promise<BrandProductsResponseDto> {
   225→		const { brand, limit, colorId, styleId, sortBy } = query;
   226→
   227→		this.logger.debug('[getBrandProducts] Starting brand products fetch', {
   228→			brand,
   229→			styleId,
   230→			colorId,
   231→			sortBy,
   232→			limit,
   233→		});
   234→
   235→		try {
   236→			const shouldFetchColor = Boolean(colorId && styleId);
   237→
   238→			const productLimit = limit ?? 30;
   239→
   240→			const [{ products, mvRecords }, currentStyleColor] = await Promise.all([
   241→				this.productHydrationService.getProductsByBrands({
   242→					brands: [brand],
   243→					limit: productLimit,
   244→				}),
   245→				shouldFetchColor
   246→					? this.styleColorsService.getStyleByStyleAndColorId({
   247→							styleId: Number(styleId),
   248→							colorId: Number(colorId),
   249→						})
   250→					: Promise.resolve(null),
   251→			]);
   252→			this.logger.debug('[getBrandProducts] Brand products fetched', {
   253→				count: products.length,
   254→			});
   255→
   256→			if (products.length === 0) {
   257→				throw new NotFoundException(`No products found for brand: ${brand}`);
   258→			}
   259→
   260→			const productsWithColor = currentStyleColor
   261→				? await (async () => {
   262→						const colorCache = new Map<
   263→							number,
   264→							ReturnType<
   265→								typeof this.productHydrationService.convertMvColorsToProductColors
   266→							>
   267→						>();
   268→						return Promise.all(
   269→							products.map(async (product) => {
   270→								const mv = mvRecords.get(product.style_id);
   271→								let colors = colorCache.get(product.style_id);
   272→								if (!colors) {
   273→									colors = this.productHydrationService.convertMvColorsToProductColors({
   274→										colors: mv?.colors ?? null,
   275→									});
   276→									colorCache.set(product.style_id, colors);
   277→								}
   278→								if (colors.length > 0 && currentStyleColor) {
   279→									const closestColorId =
   280→										await this.colorMatchWorkerService.findClosestColorId({
   281→											color: currentStyleColor,
   282→											palette: colors,
   283→										});
   284→									const closestColor = colors.find((c) => c.id === closestColorId);
   285→									if (closestColor) {
   286→										return {
   287→											...product,
   288→											color: closestColorId,
   289→											image_src: closestColor.image_url ?? product.image_src,
   290→										};
   291→									}
   292→								}
   293→								return product;
   294→							}),
   295→						);
   296→					})()
   297→				: products;
   298→
   299→			let finalProducts = productsWithColor;
   300→
   301→			if (sortBy) {
   302→				this.logger.debug('[getBrandProducts] Applying sort', { sortBy });
   303→				let currentStyleCategoryId: number | null = null;
   304→				if (sortBy === 'category' && styleId) {
   305→					const currentStyle = await this.stylesService.getStyleById({
   306→						styleId: Number(styleId),
   307→					});
   308→					currentStyleCategoryId = currentStyle?.primary_category_id ?? null;
   309→				}
   310→				finalProducts = sortStyles({
   311→					products: productsWithColor,
   312→					sortBy,
   313→					currentStyleCategoryId,
   314→				});
   315→			}
   316→
   317→			return {
   318→				product_id: styleId?.toString() ?? '',
   319→				brand_products: finalProducts.slice(0, limit),
   320→				color_id: colorId ?? null,
   321→				brand,
   322→				sort_by: sortBy ?? null,
   323→			};
   324→		} catch (error: unknown) {
   325→			const err = error instanceof Error ? error : new Error(String(error));
   326→			this.logger.error(
   327→				`Failed to get products for brand ${query.brand}, styleId ${query.styleId}: ${err.message}`,
   328→				err.stack,
   329→			);
   330→
   331→			throw err;
   332→		}
   333→	}
   334→}
